//Union-Find Tree



class Union_Find {

    vector<int> par;

    vector<int> rankmy;

public:

    Union_Find(int size){

        par = vector<int>(size);

        rankmy = vector<int>(size);

        for (int i=0; i<size; i++) {

            par[i]=i;

        }

    }



    int find(int x){

        if (par[x]==x) {

            return x;

        }

        return par[x]=find(par[x]);

    }



    void unite(int x,int y){

        x=find(x);

        y=find(y);

        if (x==y) {

            return;

        }

        if (rankmy[x]<rankmy[y]) {

            par[x]=y;

        }else{

            par[y]=x;

            if (rankmy[x]==rankmy[y]) {

                rankmy[x]++;

            }

        }

    }



    bool same(int x,int y){

        return find(x)==find(y);

    }



};



